class Dog {
  String name;
  int age;

  // This is the Constructor
  Dog(String n, int a) {
    name = n;
    age = a;
  }
}

class Main {
  public static void main(String[] args) {
    // Now we pass the data directly into new Dog()!
    Dog d1 = new Dog("Rex", 3);
    Dog d2 = new Dog("Lucy", 5);

    System.out.println(d1.name + " + " + d2.name);
  }
}
